const SeasonCard = ({season} : any) => {
    return(
        
        <div className="row">
            <div className="col-sm-6">
                <div className="card">
                    <div className="card-body">
                        <h5 className="card-title">Season: {season.startYear + " - " + season.endYear} </h5>
                        <p className="card-text">Age Group: {season.ageGroup}s</p>
                    </div>
                </div>
            </div>
        </div>        
    )
}
export default SeasonCard;
